        .a_blocappli .ei_spinnbtn {
            position: relative;
            display: inline-flex;
            align-items: center;
            max-width: 100%;
            background: #fff;
            border-radius: 0;
            min-width: -webkit-min-content;
            min-width: -moz-min-content;
            min-width: min-content;
        }

        .a_blocappli .ei_spinnbtn-focus {
            outline: 0.125rem solid #000;
        }

        .a_blocappli .ei_spinnbtn>* {
            box-sizing: border-box;
        }

        .a_blocappli .ei_spinnbtn button {
            padding: 0;
            margin: 0;
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            height: 1.875rem;
            width: 1.875rem;
            min-width: 1.875rem;
            background-color: #007a7a;
            border: 0;
        }

        .a_blocappli .ei_spinnbtn button:hover {
            background-color: #064d4e;
            cursor: pointer;
        }

        .a_blocappli .ei_spinnbtn button.ei_spinnbtn_minus {
            border-radius: 0.1875rem 0 0 0.1875rem;
        }

        .a_blocappli .ei_spinnbtn button.ei_spinnbtn_plus {
            border-radius: 0 0.1875rem 0.1875rem 0;
        }

        .a_blocappli .ei_spinnbtn button .ei_spinnbtn_minus_picto,
        .a_blocappli .ei_spinnbtn button .ei_spinnbtn_plus_picto {
            display: flex;
            justify-content: center;
            align-items: center;
            line-height: 0;
            width: inherit;
        }

        .a_blocappli .ei_spinnbtn button .ei_spinnbtn_minus_picto:before,
        .a_blocappli .ei_spinnbtn button .ei_spinnbtn_plus_picto:before {
            font-size: 1.75rem;
            font-family: fts_picto;
            speak: none;
            font-style: normal;
            font-weight: 400;
            font-variant: normal;
            text-transform: none;
            line-height: 1;
            -webkit-font-smoothing: antialiased;
            -moz-osx-font-smoothing: grayscale;
            color: #fff;
        }

        .a_blocappli .ei_spinnbtn button .ei_spinnbtn_minus_picto:before {
            content: "\F0413";
        }

        .a_blocappli .ei_spinnbtn button .ei_spinnbtn_plus_picto:before {
            content: "\F018E";
        }

        .a_blocappli .ei_spinnbtn button.disable,
        .a_blocappli .ei_spinnbtn button[disabled="disabled"] {
            background-color: #007a7a;
            opacity: 0.5;
            cursor: default;
        }

        .a_blocappli .ei_spinnbtn__inputcontainer {
            height: 1.875rem;
            display: flex;
            align-items: center;
            border-top: 1px solid #d2d0cc;
            border-bottom: 1px solid #d2d0cc;
            flex-grow: 1;
        }

        .a_blocappli .ei_spinnbtn__inputcontainer:focus,
        .a_blocappli .ei_spinnbtn__inputcontainer:focus-visible {
            outline: 0;
        }

        .a_blocappli .ei_spinnbtn.ei_spinnbtn__stepbystep .ei_spinnbtn__inputcontainer {
            background-color: #ededed;
        }

        .a_blocappli .ei_spinnbtn .ei_spinnbtn__input {
            outline: 0;
            font-size: 1em;
            border: 0 !important;
            margin: 0;
            width: 100%;
            height: 100%;
            padding: 0 15px;
            min-width: 0.5rem;
        }

        .a_blocappli .ei_spinnbtn .ei_spinnbtn__input.disable {
            background-color: #eee;
            color: #212121;
        }

        .a_blocappli .ei_spinnbtn .ei_spinnbtn__input:focus {
            border: none;
        }

        .a_blocappli .ei_spinnbtn_prefix,
        .a_blocappli .ei_spinnbtn_suffix {
            background-color: #ededed;
            display: flex;
            align-items: center;
            border-top: 1px solid #d2d0cc;
            border-bottom: 1px solid #d2d0cc;
