        .ei_button {
            border: 0;
        }

        .ei_button.cpc {
            display: block;
        }

        .ei_button.cpc .ei_btn {
            display: block;
        }

        .ei_btn {
            display: inline-block;
            border: 0;
            position: relative;
            margin: 0 0 0 10px;
            text-decoration: none;
            text-transform: initial;
            font-weight: 700;
            padding: 7px 20px 5px;
            background-color: #007a7a;
            border-radius: 0;
            transition: all 0.2s linear;
        }

        .ei_btn:hover {
            background-color: #064d4e;
            color: #fff;
        }

        .ei_btn:hover .ei_btn_label {
            text-decoration: none;
        }

        .ei_btn:focus-visible {
            background-color: #064d4e;
            color: #fff;
            outline: solid black;
            outline-offset: 2px;
        }

        .ei_btn:focus-visible .ei_btn_label {
            text-decoration: none;
        }

        .ei_btn.ei_btn_disabled {
            cursor: default;
        }

        .ei_btn.ei_btn_disabled:focus-visible,
        .ei_btn.ei_btn_disabled:hover {
            background-color: #007a7a;
        }

        .ei_btn_body {
            display: inline-block;
        }

        .ei_btn .ei_btn_body {
            color: #fff;
            position: relative;
            text-align: center;
            zoom: 1;
        }

        .ei_btn:after,
        .ei_btn:before {
            color: #fff;
            position: absolute;
            top: 50% !important;
            bottom: auto;
            -webkit-transform: translateY(-50%);
            transform: translateY(-50%);
        }

        .ei_btn:before {
            padding-left: 2px;
        }

        .ei_btn:after {
            padding-right: 2px;
        }

        .ei_btn_fn_tertiary {
            background-color: #fff;
            border: 1px solid transparent;
        }

        .ei_btn_fn_tertiary,
        .ei_btn_fn_tertiary .ei_btn_body {
            color: #767676;
        }

        .ei_btn_fn_tertiary:hover {
            background-color: #d9d9d9;
        }

        .ei_btn_fn_tertiary:hover,
        .ei_btn_fn_tertiary:hover .ei_btn_body {
            color: #414141;
        }

        .ei_btn_fn_tertiary:focus-visible {
            background-color: #fff;
        }

        .ei_btn_fn_tertiary:focus-visible,
        .ei_btn_fn_tertiary:focus-visible .ei_btn_body {
            color: #0068d8;
        }

        .ei_btn_disabled a.ei_btn,
        a.ei_btn_disabled {
            cursor: default;
            pointer-events: none;
            opacity: 0.5;
        }

        .ei_btn_disabled a.ei_btn .ei_btn_label,
        a.ei_btn_disabled .ei_btn_label {
            text-decoration: none;
        }

        .ei_btn_disabled a.ei_btn .ei_btn_blcorn,
