        .bloctelft {
            margin: 0 0 3px 0;
            width: 160px;
        }

        .bloctelft .num {
            padding: 1px 0 0 70px;
            letter-spacing: -1px;
            font-size: 11px;
            margin: 0;
            font-weight: 700;
            font-family: Verdana, Helvetica, sans-serif;
        }

        .bloctelft .tarif {
            text-align: right;
            font-size: 80%;
            color: #000;
            margin: 0;
            font-weight: 700;
        }

        .bloctelft:not(.bloctel_css) .num {
            line-height: 13px;
        }

        .bloctel_css {
            display: inline-block;
            width: auto;
            border-radius: 30px;
            position: relative;
            background: 0 0;
            background-color: #fff;
            margin-bottom: 16px;
        }

        .bloctel_css .num {
            padding: 0 !important;
            padding-right: 12px !important;
            margin: 0;
            display: flex;
            align-items: center;
            font-family: Arial, Helvetica, sans-serif;
            font-weight: 700;
        }

        .bloctel_css .num_title {
            letter-spacing: 0.5px;
            margin-right: 10px;
            border-radius: 30px;
            color: #fff;
            font-weight: 700;
            padding: 5px 15px;
        }

        .bloctel_css .num:after {
            content: "";
            position: absolute;
            border-radius: 30px;
            left: 0;
            top: 0;
            right: 0;
            bottom: 0;
        }

        .bloctel_css .tarif {
            color: #9ea3a6;
            position: absolute;
            text-transform: uppercase;
            top: 30px;
            width: auto;
            font-size: 10px;
            margin: 0;
            right: 0.625rem;
        }

        .bloctel_css .tarif .num:before {
            padding: 0.3125rem 0.5rem 0.3125rem 1.875rem;
        }

        .bloctel_css.cristal .num_title {
            background-color: #9ea3a6;
            border: 1px solid #9ea3a6;
        }

        .bloctel_css.cristal .num:after {
            border: 2px solid #9ea3a6;
        }

        .bloctel_css:after,
        .bloctel_css:before {
            content: " ";
            position: absolute;
            box-sizing: inherit;
            top: 50%;
            -webkit-transform: translateY(-50%);
            transform: translateY(-50%);
        }

        .bloctel_css:before {
            border: solid transparent;
            border-color: transparent transparent transparent #fff;
            width: 0;
            height: 0;
            pointer-events: none;
        }

        .bloctel_css:after {
            border: 2px solid #fff;
            border-radius: 50%;
            z-index: 10;
            left: 0.375rem;
        }

        .bloctel_css.xsmall:before {
            border-width: 0.1875rem 0.1875rem 0.1875rem 0.375rem;
            left: 0.6875rem;
        }

        .bloctel_css.xsmall:after {
            height: 0.625rem;
            width: 0.625rem;
        }

        .bloctel_css.xsmall .num {
            font-size: 12px;
            font-weight: 800;
        }

        .bloctel_css.xsmall .num_title {
            padding: 0.1875rem 0.375rem 0.125rem 1.5rem;
        }

        .bloctel_css.xsmall .tarif {
            top: 22px;
        }

        .bloctel_css.small:before {
            border-width: 0.375rem 0.375rem 0.375rem 0.625rem;
            left: 0.75rem;
        }

        .bloctel_css.small:after {
            height: 1rem;
            width: 1rem;
        }

        .bloctel_css.small .num {
            font-size: 15px;
        }

        .bloctel_css.small .num_title {
            padding: 0.3125rem 0.5rem 0.3125rem 1.875rem;
        }

        .bloctel_css.small .tarif {
            top: 30px;
        }

        .bloctel_css.medium {
            border-radius: 20px;
        }

        .bloctel_css.medium:before {
            border-width: 0.5rem 0.5rem 0.5rem 0.9375rem;
            left: 0.8125rem;
        }

        .bloctel_css.medium:after {
            height: 1.375rem;
            width: 1.375rem;
        }

        .bloctel_css.medium .num {
            font-size: 20px;
        }

        .bloctel_css.medium .num_title {
            font-size: 1.25rem;
            padding: 0.3125rem 0.9375rem 0.3125rem 2.25rem;
        }

        .bloctel_css.medium .tarif {
            top: 37px;
        }

        .bloctel_css.large {
            border-radius: 25px;
        }

        .bloctel_css.large:before {
            border-width: 0.625rem 0.625rem 0.625rem 1.0625rem;
            left: 1rem;
        }

        .bloctel_css.large:after {
            height: 1.75rem;
            width: 1.75rem;
        }

        .bloctel_css.large .num {
            font-size: 24px;
        }

        .bloctel_css.large .num_title {
            border-radius: 1.25rem;
            padding: 0.3125rem 0.9375rem 0.3125rem 2.875rem;
        }

        .bloctel_css.large .tarif {
            top: 42px;
        }

        .bloctel_css.xlarge {
            border-radius: 30px;
        }

        .bloctel_css.xlarge:before {
            border-width: 1rem 1rem 1rem 1.5625rem;
            left: 1.25rem;
        }

        .bloctel_css.xlarge:after {
            height: 2.5rem;
            width: 2.5rem;
        }

        .bloctel_css.xlarge .num {
            font-size: 43px;
        }

        .bloctel_css.xlarge .num_title {
            border-radius: 1.875rem;
            padding: 0.3125rem 0.9375rem 0.3125rem 3.75rem;
        }

        .bloctel_css.xlarge .tarif {
            top: 65px;
        }

