        #ei_tpl_search,
        #ei_tpl_searchmobil {
            justify-content: flex-end;
        }

        #ei_tpl_search {
            padding: 12px 16px 12px 8px;
            flex-grow: 2;
        }

        #ei_tpl_searchmobil {
            padding: 12px 8px;
        }

        .ei_srchbar_form {
            height: 40px;
        }

        #ei_tpl_search .ei_srchbar_form {
            width: 230px;
        }

        #ei_tpl_searchmobil .ei_srchbar_form {
            width: 100%;
        }

        .ei_srchbar_form {
            display: flex;
            justify-content: space-between;
            position: relative;
            padding: 0;
            background-color: #ececec;
            border-radius: 5px;
            transition: width 0.5s ease;
        }

        .ei_srchbar_button,
        .ei_srchbar_input {
            border: 0;
            outline: 0;
        }

        .ei_srchbar_input {
            width: 100%;
            margin: 0;
            padding: 8px 8px 8px 16px;
            background-color: transparent;
            box-shadow: none;
        }

        #ei_tpl_searchmobil .ei_srchbar_input {
            font-size: 16px;
        }

        .ei_srchbar_input,
        .ei_srchbar_input::-webkit-input-placeholder {
            color: #565656;
            transition: color 0.3s ease;
        }

        .ei_srchbar_input,
        .ei_srchbar_input::-moz-placeholder {
            color: #565656;
            transition: color 0.3s ease;
        }

        .ei_srchbar_input,
        .ei_srchbar_input::-ms-input-placeholder {
            color: #565656;
            transition: color 0.3s ease;
        }

        .ei_srchbar_input,
        .ei_srchbar_input::placeholder {
            color: #565656;
            transition: color 0.3s ease;
        }

        .ei_srchbar_input::-moz-placeholder {
            opacity: 1;
        }

        .ei_srchbar_input:focus {
            background-color: transparent;
        }

        .ei_srchbar_input:focus::-webkit-input-placeholder {
            color: transparent;
        }

        .ei_srchbar_input:focus::-moz-placeholder {
            color: transparent;
        }

        .ei_srchbar_input:focus::-ms-input-placeholder {
            color: transparent;
        }

        .ei_srchbar_input:focus::placeholder {
            color: transparent;
        }

        .ei_srchbar_button {
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            display: inline-flex;
            justify-content: center;
            align-items: center;
            width: 40px;
            height: 100%;
            border-radius: 0 5px 5px 0;
            background-color: transparent;
            color: #000;
            transition: background-color 0.3s;
        }

        .ei_srchbar_button:focus,
        .ei_srchbar_button:hover {
            color: #099;
        }

        .ei_srchbar_button:focus {
            outline: 1px dotted grey;
        }

        .ei_srchbar_button:focus,
        .ei_srchbar_button:hover,
        .ei_srchbar_input:focus~.ei_srchbar_button {
            background-color: #d8d8d8;
        }

        .ei_srchbar_glyph {
            position: relative;
        }

        .ei_srchbar_glyph:before {
            content: "\F043D";
            font-family: fts_picto;
            font-size: 22px;
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
        }

        .autocomplete_search {
            display: none;
            width: 100%;
            padding: 16px 0 8px;
            position: absolute;
            top: 32px;
            left: 0;
            right: 0;
            border-radius: 0 0 5px 5px;
            box-shadow: 0 0 4px 0 rgba(86, 86, 86, 0.5);
            background-color: #fff;
            z-index: -1;
        }

        .autocomplete_search ul {
            margin: 0;
        }

        .autocomplete_search ul li {
            list-style: none;
        }

        .autocomplete_search a {
            display: block;
            position: relative;
            padding: 4px 8px 4px 28px;
            color: #565656;
            text-decoration: none;
        }

        .autocomplete_search a:focus,
        .autocomplete_search a:hover,
        .autocomplete_search li.ei_search-focus a {
            color: #fff;
        }

        .autocomplete_search .srch-search-link_picto_list {
            position: absolute;
            top: 2px;
            left: 6px;
        }

        .autocomplete_search .srch-search-link_picto_list:before {
            content: "\F043D";
            font-size: 16px;
            font-size: 1rem;
        }

        .autocomplete_search {
            margin-left: 1px;
            width: calc(100% - 2px);
        }

        .autocomplete_search a:focus,
        .autocomplete_search a:hover,
        .autocomplete_search li.ei_search-focus a {
            background-color: #767676;
        }

        .autocomplete_search a:focus {
            outline: 2px solid #000;
            outline-offset: -1px;
        }

        #CYB1_VOC {
            width: 68px;
            position: relative;
