        .ei_menu__burger:focus {
            outline: thin dotted;
        }

        .ei_menu__burgerlabel {
            display: block;
            color: #6c6c6c;
            font-weight: 400;
            text-align: center;
            text-transform: uppercase;
            padding-top: 5px;
            font-size: 13px;
            font-size: 0.8125rem;
        }

        .ei_menu__burgerbox {
            position: relative;
            display: inline-flex;
            justify-content: center;
            width: 37px;
            height: 23px;
        }

        .ei_menu__burgerline,
        .ei_menu__burgerline:after,
        .ei_menu__burgerline:before {
            position: absolute;
            height: 5px;
            border-radius: 5px;
            background-color: #099;
        }

        .ei_menu__burgerline {
            width: 35px;
            top: 50%;
            left: calc((100% - 35px) / 2);
            transition: background-color 75ms ease, -webkit-transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19);
            transition: background-color 75ms ease, transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19);
            transition: background-color 75ms ease, transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19), -webkit-transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19);
        }

        .ei_menu__burgerline:after,
        .ei_menu__burgerline:before {
            content: "";
            left: 0;
        }

        .ei_menu__burgerline:before {
            width: 35px;
            top: -9px;
            transition: background-color 75ms ease, top 75ms ease 0.12s, opacity 75ms ease;
        }

        .ei_menu__burgerline:after {
            width: 35px;
            bottom: -9px;
            transition: background-color 75ms ease, bottom 75ms ease 0.12s, -webkit-transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19);
            transition: background-color 75ms ease, bottom 75ms ease 0.12s, transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19);
            transition: background-color 75ms ease, bottom 75ms ease 0.12s, transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19), -webkit-transform 75ms cubic-bezier(0.55, 0.055, 0.675, 0.19);
        }

        .ei_menumobil .ei_menu__burgerbox .ei_menu__burgerline {
            width: 35px;
            transition: background-color 75ms ease, -webkit-transform 75ms cubic-bezier(0.215, 0.61, 0.355, 1) 0.12s;
            transition: background-color 75ms ease, transform 75ms cubic-bezier(0.215, 0.61, 0.355, 1) 0.12s;
            transition: background-color 75ms ease, transform 75ms cubic-bezier(0.215, 0.61, 0.355, 1) 0.12s, -webkit-transform 75ms cubic-bezier(0.215, 0.61, 0.355, 1) 0.12s;
            -webkit-transform: rotate(45deg);
            transform: rotate(45deg);
        }

        .ei_menumobil .ei_menu__burgerbox .ei_menu__burgerline:before {
            top: 0;
            transition: background-color 75ms ease, top 75ms ease, opacity 75ms ease 0.12s;
            opacity: 0;
        }

        .ei_menumobil .ei_menu__burgerbox .ei_menu__burgerline:after {
