            background-position: center center;
            background-repeat: no-repeat;
            background-size: 70px;
            position: absolute;
            height: 70px;
            width: 70px;
            top: 0;
            left: 0;
            content: " ";
            -webkit-animation: 1s rotateAnim cubic-bezier(0.52, 0.23, 0.54, 0.83) infinite;
            animation: 1s rotateAnim cubic-bezier(0.52, 0.23, 0.54, 0.83) infinite;
