        #frmDoc div#pSelection {
            background-color: #eee;
            padding: 5px;
        }

        #frmDoc #Table1>tbody>tr>td {
            border: 0;
        }

        #frmDoc #Table1 #Table2 {
            padding-top: 10px;
        }

        #frmDoc #Table1 #Table2 td {
            padding: 0;
        }

        #frmDoc #Table1 table caption {
            background-color: #fff;
            color: #000;
            font-family: Roboto, Arial, Helvetica, sans-serif;
            font-weight: 500;
            font-size: 1.538em;
            text-align: left;
            padding: 6px 12px 6px;
        }

        #frmDoc ul.menu {
            padding: 0;
            margin: 0;
        }

        #frmDoc ul.menu li {
            border-left: 3px solid #b8b8b8;
            border-top: 1px solid #ddd;
            padding: 0;
            transition: all 0.2s linear;
        }

        #frmDoc ul.menu li:before {
            content: "";
            background-color: transparent;
        }

        #frmDoc ul.menu li:hover {
            border-left: 3px solid #0f228b;
            background-color: #ddd;
        }

        #frmDoc ul.menu li a {
            color: #414141;
            font-family: Roboto, Arial, Helvetica, sans-serif;
            font-weight: 500;
            font-size: 1em;
            padding: 10px;
            text-decoration: none;
            display: inline-block;
        }

        #frmDoc ul.menu li.sel {
            border-left: 3px solid #0f228b;
            border-right: 3px solid #0f228b;
            background-color: #ddd;
        }

        #frmDoc ul.menu li.sel:after {
            content: "";
            border-top: 8px solid transparent;
            border-bottom: 8px solid transparent;
            border-left: 8px solid #0f228b;
            width: 0;
            height: 0;
            position: absolute;
            right: -11px;
            top: 12px;
        }

        #frmDoc ul.menu li.sel a {
            font-family: Roboto, Arial, Helvetica, sans-serif;
            font-weight: 700;
            font-size: 1em;
        }

        @media screen and (max-width: 999px) {
            #frmDoc ul.menu li.sel::after {
                border-left: 0;
            }

            #frmDoc #Table1 {
                display: block;
            }

            #frmDoc #Table1>tbody {
                display: block;
            }

            #frmDoc #Table1>tbody>tr {
                display: block;
            }

            #frmDoc #Table1>tbody>tr>td,
            #frmDoc #Table1>tbody>tr>th {
                display: block;
                width: 100%;
            }
        }

        #frmDoc ul.menu li.sel {
            border-right: 0;
        }

        #frmDoc ul.menu li.sel:after {
            border: 0;
        }

        #frmDoc ul.menu li.sel:before {
            border-bottom: 5px solid transparent;
            border-left: 5px solid #0f228b;
            border-top: 5px solid transparent;
            bottom: calc(50% - 15px);
            content: "";
            height: 0;
            position: absolute;
            left: 0;
            z-index: 100;
            width: 0;
        }

        #frmDoc #pTitre2 a.ei_titlebackbutton {
            float: left;
        }

        #frmDoc #pTitre2 a.ei_titlebackbutton:before {
            top: -5px;
        }

        #frmDoc #Table2 {
            border-right: 1px solid #b8b8b8;
        }

