    <style type="text/css">
        .ei_msgconv {
            display: flex;
            flex-direction: column;
            font-size: 13px;
            height: 715px;
            overflow: hidden;
            background: #e6f5f6;
        }

        .ei_msgconv--live {
            background: #b4e2e3;
        }

        .ei_msgconv__wait {
            padding: 12px;
        }

        .ei_msgconv__scroll-content {
            flex: 1 1 auto;
            overflow: auto;
        }

        .ei_msgconv__scroll-content .mCSB_container {
            padding: 0;
        }

        .ei_msgconv__scroll-content .mCSB_scrollTools {
            margin: 4px 0;
        }

        .ei_msgconv__scroll-content:not(.mCustomScrollbar) {
            padding: 12px;
        }

        .ei_msgconv__bottom {
            position: relative;
        }

        .ei_msgconv__bottom .dw_acroot {
            position: absolute;
            top: -14px;
            right: 0;
            left: 0;
            z-index: 10;
        }

        .ei_msgconv__bottom span.dw_ac {
            display: inline-block;
            width: 163px;
        }

        .ei_msgconv__bottom .ei_razinherits {
            list-style-type: none;
            background: #fff;
            box-shadow: 0 -2px 3px rgba(7, 120, 126, 0.3);
            border: 0;
            cursor: default;
            line-height: normal;
            font-size: 1em;
            top: auto;
            right: 0;
            bottom: 0;
            left: 0;
            width: auto;
        }

        .ei_msgconv__bottom .dw_ac_list ul {
            padding: 0;
            margin: 0;
        }

        .ei_msgconv__bottom .dw_ac_list ul li {
            cursor: pointer;
            position: relative;
            list-style: none;
            text-align: left;
            white-space: normal;
            padding: 8px 8px 8px 32px;
            color: #07787e;
            background-color: transparent;
            outline: 0;
            transition: background-color 0.3s linear, right 0.3s linear, left 0.3s linear, width 0.3s linear, height 0.3s linear;
        }

        .ei_msgconv__bottom .dw_ac_list ul li:focus,
        .ei_msgconv__bottom .dw_ac_list ul li:hover,
        .ei_msgconv__bottom .dw_ac_list ul li[aria-selected="true"] {
            background-color: #ebfeff;
        }

        .ei_msgconv__bottom .dw_ac_list ul li:focus:after,
        .ei_msgconv__bottom .dw_ac_list ul li:hover:after,
        .ei_msgconv__bottom .dw_ac_list ul li[aria-selected="true"]:after {
            right: 0;
            left: 0;
            width: 100%;
            height: 2px;
        }

        .ei_msgconv__bottom .dw_ac_list ul li:before {
            position: absolute;
            top: 50%;
            left: 8px;
            -webkit-transform: translateY(-50%);
            transform: translateY(-50%);
            content: "\F043D";
            font-family: fts_picto;
            color: #b2dee1;
            font-size: 20px;
        }

        .ei_msgconv__bottom .dw_ac_list ul li:after {
            content: "";
            position: absolute;
            right: 8px;
            left: 8px;
            bottom: 0;
            background-color: #d2e2e2;
            height: 1px;
            width: calc(100% - 16px);
        }

        .ei_msgconv__write {
            position: relative;
            z-index: 1;
            padding: 8px;
            box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
            background: #fff;
        }

        .ei_msgconv__write textarea {
            padding: 12px 16px 12px 32px;
            margin: 0;
            font-size: 14px !important;
            font-weight: 600;
            line-height: 16px !important;
            height: 40px;
            flex: 1 1 auto;
            background: #def2f3;
            border: 0;
            border-radius: 20px;
            color: rgba(7, 120, 126, 0.7);
            box-sizing: border-box;
            resize: none;
        }

        .ei_msgconv__write textarea::-webkit-input-placeholder {
            color: rgba(7, 120, 126, 0.7);
            font-weight: 600;
        }

        .ei_msgconv__write textarea::-moz-placeholder {
            color: rgba(7, 120, 126, 0.7);
            font-weight: 600;
        }

        .ei_msgconv__write textarea::-ms-input-placeholder {
            color: rgba(7, 120, 126, 0.7);
            font-weight: 600;
        }

        .ei_msgconv__write textarea::placeholder {
            color: rgba(7, 120, 126, 0.7);
            font-weight: 600;
        }

        .ei_msgconv__write textarea::-moz-placeholder {
