        @-webkit-keyframes glypheOpacity {
            0% {
                opacity: 0;
            }

            50% {
                opacity: 0;
            }

            100% {
                opacity: 1;
            }
        }

        @keyframes glypheOpacity {
            0% {
                opacity: 0;
            }

            50% {
                opacity: 0;
            }

            100% {
                opacity: 1;
            }
        }

        .ei_slide .ei_ircc_notification {
            background-color: #c50307;
            border-radius: 20px;
            color: #fff;
            display: none;
            font-size: 10px;
            font-weight: 600;
            height: 16px;
            left: -5px;
            line-height: 16px;
            min-width: 14px;
            padding: 0 1px;
            position: absolute;
            text-align: center;
            top: 0;
            width: auto;
        }

        .ei_slide .picto_interlocuteur,
        .ei_slide .picto_ircc,
        .ei_slide .picto_ircc_dots {
            height: 40px;
            position: relative;
            text-align: left;
            width: 40px;
        }

        .ei_slide .picto_interlocuteur:before,
        .ei_slide .picto_ircc:before,
        .ei_slide .picto_ircc_dots:before {
            left: 0;
            position: absolute;
            top: 0;
            font-family: fts_picto;
            color: #fff;
            font-size: 40px;
        }

        .ei_slide .picto_interlocuteur:before {
            content: "\F0AA8";
        }

        .ei_slide .picto_ircc:before {
            content: "\F0AAA";
        }

        .ei_slide .picto_ircc .irccbubble__dots {
            display: flex;
            flex-direction: row;
            left: 11px;
            position: absolute;
            top: 19px;
            -webkit-animation-name: glypheOpacity;
            animation-name: glypheOpacity;
            -webkit-animation-duration: 2s;
            animation-duration: 2s;
        }

        .ei_slide .picto_ircc .irccbubble__dot {
            display: block;
            height: 8px;
            width: 8px;
            -webkit-transform: scale(0.5);
            transform: scale(0.5);
            border-radius: 50px;
            margin: -2px -1px;
            background-color: #fff;
        }

        .ei_slide .picto_ircc .irccbubble__dot1,
        .ei_slide .picto_ircc .irccbubble__dot2,
        .ei_slide .picto_ircc .irccbubble__dot3 {
            -webkit-transform-origin: center center;
            transform-origin: center center;
            -webkit-animation-name: dotPulsation;
            animation-name: dotPulsation;
            -webkit-animation-duration: 30s;
            animation-duration: 30s;
            -webkit-animation-iteration-count: infinite;
            animation-iteration-count: infinite;
        }

        .ei_slide .picto_ircc .irccbubble__dot1 {
            -webkit-animation-delay: 2.3s;
            animation-delay: 2.3s;
        }

        .ei_slide .picto_ircc .irccbubble__dot2 {
            -webkit-animation-delay: 2.6s;
            animation-delay: 2.6s;
        }

        .ei_slide .picto_ircc .irccbubble__dot3 {
            -webkit-animation-delay: 2.9s;
            animation-delay: 2.9s;
        }

        @-webkit-keyframes dotPulsation {
            0% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            1.75% {
                -webkit-transform: scale(1);
                transform: scale(1);
            }

            3.5% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            5% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            6.75% {
                -webkit-transform: scale(1);
                transform: scale(1);
            }

            8.5% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            100% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }
        }

        @keyframes dotPulsation {
            0% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            1.75% {
                -webkit-transform: scale(1);
                transform: scale(1);
            }

            3.5% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            5% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            6.75% {
                -webkit-transform: scale(1);
                transform: scale(1);
            }

            8.5% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }

            100% {
                -webkit-transform: scale(0.5);
                transform: scale(0.5);
            }
        }

